; Test case 1: gep with nuw flag
define i1 @test1(i8* %ptr, i64 %idx) {
  %gep = getelementptr inbounds i8, i8* %ptr, i64 %idx
  %cmp = icmp ugt i8* %gep, %ptr
  ret i1 %cmp
}

; Test case 2: gep with nusw flag (inbounds implies nusw)
define i1 @test2(i8* %ptr, i64 %idx) {
  %gep = getelementptr inbounds i8, i8* %ptr, i64 %idx
  %cmp = icmp ugt i8* %gep, %ptr
  ret i1 %cmp
}

; Test case 3: gep with both nuw and nusw
define i1 @test3(i8* %ptr, i64 %idx) {
  %gep = getelementptr inbounds i8, i8* %ptr, i64 %idx
  %cmp = icmp ugt i8* %gep, %ptr
  ret i1 %cmp
}

; Test case 4: gep without any nowrap flags
define i1 @test4(i8* %ptr, i64 %idx) {
  %gep = getelementptr i8, i8* %ptr, i64 %idx
  %cmp = icmp ugt i8* %gep, %ptr
  ret i1 %cmp
}
EOF"}

